import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        String line;
        // read first non‑empty line
        while ((line = br.readLine()) != null && line.trim().isEmpty()) {
            // skip
        }
        if (line == null) {
            System.out.print("");
            return;
        }
        StringTokenizer stFirst = new StringTokenizer(line);
        int tokenCount = stFirst.countTokens();
        int T;
        boolean firstLineIsDim = false;
        String dimLine = null;
        if (tokenCount == 1) {
            T = Integer.parseInt(stFirst.nextToken());
        } else {
            // first line already contains n and m, treat as a single test case
            T = 1;
            firstLineIsDim = true;
            dimLine = line;
        }
        for (int caseIdx = 0; caseIdx < T; caseIdx++) {
            // obtain dimensions line
            String dim;
            if (firstLineIsDim && caseIdx == 0) {
                dim = dimLine;
            } else {
                // read next non‑empty line for dimensions
                while ((dim = br.readLine()) != null && dim.trim().isEmpty()) {
                    // skip empty lines
                }
                if (dim == null) break; // no more input
            }
            StringTokenizer st = new StringTokenizer(dim);
            int n = Integer.parseInt(st.nextToken());
            int m = Integer.parseInt(st.nextToken());
            int[][] dist = new int[n][m];
            for (int[] row : dist) Arrays.fill(row, -1);
            ArrayDeque<int[]> q = new ArrayDeque<>();
            // read matrix rows
            for (int i = 0; i < n; i++) {
                String rowLine;
                while ((rowLine = br.readLine()) != null && rowLine.trim().isEmpty()) {
                    // skip empty lines
                }
                StringTokenizer rowTok = new StringTokenizer(rowLine);
                for (int j = 0; j < m; j++) {
                    int val = Integer.parseInt(rowTok.nextToken());
                    if (val == 0) {
                        dist[i][j] = 0;
                        q.add(new int[]{i, j});
                    }
                }
            }
            int[] dr = {0, 0, 1, -1};
            int[] dc = {1, -1, 0, 0};
            while (!q.isEmpty()) {
                int[] cur = q.poll();
                int r = cur[0], c = cur[1];
                for (int k = 0; k < 4; k++) {
                    int nr = r + dr[k];
                    int nc = c + dc[k];
                    if (nr >= 0 && nr < n && nc >= 0 && nc < m && dist[nr][nc] == -1) {
                        dist[nr][nc] = dist[r][c] + 1;
                        q.add(new int[]{nr, nc});
                    }
                }
            }
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < m; j++) {
                    out.append(dist[i][j]);
                    if (j + 1 < m) out.append(' ');
                }
                out.append('\n');
            }
        }
        System.out.print(out.toString());
    }
}

